mapper.select:
select ws.id as warehouseSkuId, d.id as dishId, d.name as dishName, d.image as image, c.name as categoryName, ifnull(ws.stock, 0) as currentStock, ifnull(ws.status, 0) as status from dish d left join category c on c.id = d.category_id left join warehouse_sku ws on ws.dish_id = d.id and ws.warehouse_id = #{warehouseId} where d.status = 1
and d.name like concat('%', #{name}, '%')
order by d.id desc limit #{offset}, #{pageSize}
